import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"TongAgents — Tool System","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/tongagents/tool-system.md","filePath":"research/agents/tongagents/tool-system.md"}'),i={name:"research/agents/tongagents/tool-system.md"};function s(l,e,r,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="tongagents-—-tool-system" tabindex="-1">TongAgents — Tool System <a class="header-anchor" href="#tongagents-—-tool-system" aria-label="Permalink to &quot;TongAgents — Tool System&quot;">​</a></h1><blockquote><p>⚠️ <strong>Limited information available.</strong> No source code or API documentation has been published. Tool capabilities are inferred from Terminal-Bench 2.0 task requirements.</p></blockquote><h2 id="what-terminal-bench-tasks-require" tabindex="-1">What Terminal-Bench Tasks Require <a class="header-anchor" href="#what-terminal-bench-tasks-require" aria-label="Permalink to &quot;What Terminal-Bench Tasks Require&quot;">​</a></h2><p>Terminal-Bench 2.0 covers 89 tasks across several categories. To score 80.2%, TongAgents must have tools for:</p><h3 id="shell-execution-required" tabindex="-1">Shell Execution (Required) <a class="header-anchor" href="#shell-execution-required" aria-label="Permalink to &quot;Shell Execution (Required)&quot;">​</a></h3><p>Every Terminal-Bench task involves CLI interaction. The agent must have:</p><ul><li><strong>Command execution</strong> — run arbitrary shell commands and capture stdout/stderr</li><li><strong>Exit code handling</strong> — detect success vs failure from return codes</li><li><strong>Interactive command support</strong> — handle commands that prompt for input (e.g., <code>apt install -y</code>)</li><li><strong>Long-running command management</strong> — timeouts, background processes</li></ul><h3 id="file-system-operations-required" tabindex="-1">File System Operations (Required) <a class="header-anchor" href="#file-system-operations-required" aria-label="Permalink to &quot;File System Operations (Required)&quot;">​</a></h3><p>Many tasks involve reading and writing configuration files:</p><ul><li><strong>File reading</strong> — view file contents, search within files</li><li><strong>File writing/editing</strong> — create, modify, append to files</li><li><strong>Directory navigation</strong> — list, create, traverse directory structures</li><li><strong>Permission management</strong> — chmod, chown operations</li></ul><h3 id="task-categories-and-implied-tools" tabindex="-1">Task Categories and Implied Tools <a class="header-anchor" href="#task-categories-and-implied-tools" aria-label="Permalink to &quot;Task Categories and Implied Tools&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Terminal-Bench Category</th><th>Implied Tool Capabilities</th></tr></thead><tbody><tr><td>Server configuration</td><td>Service management, config file editing, networking</td></tr><tr><td>Debugging</td><td>Log analysis, process inspection, strace/ltrace</td></tr><tr><td>Security</td><td>User management, firewall rules, certificate handling</td></tr><tr><td>Data science</td><td>Python/R execution, package management, data parsing</td></tr><tr><td>Compilation</td><td>Build systems (make, cmake), dependency resolution</td></tr></tbody></table><h2 id="likely-tool-architecture" tabindex="-1">Likely Tool Architecture <a class="header-anchor" href="#likely-tool-architecture" aria-label="Permalink to &quot;Likely Tool Architecture&quot;">​</a></h2><p>Given the multi-agent hypothesis, tools are probably:</p><ol><li><strong>Centralized</strong> — a shared tool interface that any agent can call</li><li><strong>Sandboxed</strong> — executed within the Terminal-Bench Docker environment</li><li><strong>Instrumented</strong> — tool calls and outputs are logged for the observation step</li></ol><h3 id="minimal-tool-set-high-confidence" tabindex="-1">Minimal Tool Set (High Confidence) <a class="header-anchor" href="#minimal-tool-set-high-confidence" aria-label="Permalink to &quot;Minimal Tool Set (High Confidence)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>- shell_execute(command, timeout)    → Run a shell command</span></span>
<span class="line"><span>- file_read(path)                    → Read file contents</span></span>
<span class="line"><span>- file_write(path, content)          → Write/overwrite a file</span></span>
<span class="line"><span>- file_edit(path, old, new)          → Surgical file editing</span></span></code></pre></div><h3 id="extended-tool-set-moderate-confidence" tabindex="-1">Extended Tool Set (Moderate Confidence) <a class="header-anchor" href="#extended-tool-set-moderate-confidence" aria-label="Permalink to &quot;Extended Tool Set (Moderate Confidence)&quot;">​</a></h3><p>More sophisticated agents often include:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>- shell_execute_background(command)  → Run without blocking</span></span>
<span class="line"><span>- file_search(pattern, directory)    → Find files by name/content</span></span>
<span class="line"><span>- process_list()                     → List running processes</span></span>
<span class="line"><span>- network_check(host, port)          → Verify service availability</span></span></code></pre></div><h2 id="model-specific-tool-calling" tabindex="-1">Model-Specific Tool Calling <a class="header-anchor" href="#model-specific-tool-calling" aria-label="Permalink to &quot;Model-Specific Tool Calling&quot;">​</a></h2><p>The performance gap between Gemini 3.1 Pro (80.2%) and Claude Opus 4.6 (~71.9%) could be partly explained by differences in <strong>tool calling reliability</strong>:</p><ul><li>Gemini and Claude have different tool-calling APIs and conventions</li><li>Some models are better at structured output (JSON tool calls) than others</li><li>The agent must translate between its internal tool representation and each model&#39;s format</li></ul><h2 id="what-we-don-t-know" tabindex="-1">What We Don&#39;t Know <a class="header-anchor" href="#what-we-don-t-know" aria-label="Permalink to &quot;What We Don&#39;t Know&quot;">​</a></h2><ul><li>Whether tools are defined as function schemas or embedded in prompts</li><li>The exact set of tools available to the agent</li><li>Whether the agent can dynamically discover or create tools</li><li>How tool errors are surfaced to the reasoning loop</li><li>Whether there are domain-specific tools beyond basic shell/file operations</li><li>If the agent uses any form of tool documentation or few-shot examples for tool use</li></ul>`,25)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
